# Check the mode of an existing policy definition
az policy definition show \
  --name corp-require-tags \
  --management-group mg-corp \
  --query 'mode' -o tsv

# Example: using mode 'All' for a subscription-level resource
# The Microsoft.Resources/subscriptions resource type is NOT included in 'Indexed'
# If you set mode to 'Indexed', this policy never fires
az policy definition create \
  --name require-security-contact \
  --mode All \
  --rules '{
    "if": {
      "allOf": [
        { "field": "type", "equals": "microsoft.security/securitycontacts" }
      ]
    },
    "then": { "effect": "AuditIfNotExists", "details": {
      "type": "microsoft.security/securitycontacts",
      "existenceScope": "Subscription",
      "existenceCondition": { "field": "microsoft.security/securitycontacts/email", "notEquals": "" }
    } }
  }'

# Resource group policies also require mode 'All'
# Policies that check resource group tags should use mode 'All' and
# filter on type = 'Microsoft.Resources/subscriptions/resourceGroups'
